1	package device
2	
3	import (
4		"io"
5		"net/netip"
6		"testing"
7		"time"
8	
9		"github.com/7mind/wanbond/internal/log"
10		"github.com/7mind/wanbond/internal/telemetry"
11	)
12	
13	// fakeHealth is a hand-driven per-path liveness verdict so a test can force the exact
14	// hub-loss (all DOWN) / partial (some UP) states the controller must distinguish.
15	type fakeHealth struct{ state telemetry.PathState }
16	
17	func (f *fakeHealth) State() telemetry.PathState { return f.state }
18	
19	// recordingRemote records the last endpoint SetPeerRemote was pointed at and how many
20	// times, standing in for the live Bind so the switch is observable without an engine.
21	type recordingRemote struct {
22		last  netip.AddrPort
23		calls int
24	}
25	
26	func (r *recordingRemote) SetPeerRemote(ap netip.AddrPort) {
27		r.last = ap
28		r.calls++
29	}
30	
31	func discardLogger(t *testing.T) log.Logger {
32		t.Helper()
33		lg, err := log.New("error", io.Discard)
34		if err != nil {
35			t.Fatalf("build logger: %v", err)
36		}
37		return lg
38	}
39	
40	func mustEndpoints(t *testing.T, ss ...string) []netip.AddrPort {
41		t.Helper()
42		eps := make([]netip.AddrPort, len(ss))
43		for i, s := range ss {
44			ap, err := netip.ParseAddrPort(s)
45			if err != nil {
46				t.Fatalf("parse endpoint %q: %v", s, err)
47			}
48			eps[i] = ap
49		}
50		return eps
51	}
52	
53	const testSettle = 3 * time.Second
54	
55	// TestHubFailoverSwitchesOnHubLoss is the core acceptance: with a 2-endpoint list,
56	// forcing ALL paths to endpoint#1 DOWN switches the peer remote to endpoint#2 AND
57	// initiates exactly one re-handshake — while ANY path being UP takes no action at all
58	// (hub loss = EVERY path down, distinct from a single path failing).
59	func TestHubFailoverSwitchesOnHubLoss(t *testing.T) {
60		eps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820")
61		hp := []hubHealth{&fakeHealth{telemetry.StateUp}, &fakeHealth{telemetry.StateUp}}
62		rem := &recordingRemote{}
63		handshakes := 0
64		clk := &fakeClock{now: time.Unix(1000, 0)}
65		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
66	
67		// Both paths UP → no failover, even long after the settle dwell.
68		clk.advance(10 * time.Second)
69		h.check()
70		if rem.calls != 0 || handshakes != 0 {
71			t.Fatalf("failover fired while a path was UP: remote switches=%d handshakes=%d", rem.calls, handshakes)
72		}
73		if h.idx != 0 {
74			t.Fatalf("active index moved off 0 while a path was up: %d", h.idx)
75		}
76	
77		// Hub loss: every path DOWN. The settle dwell since construction has elapsed (+10s).
78		hp[0].(*fakeHealth).state = telemetry.StateDown
79		hp[1].(*fakeHealth).state = telemetry.StateDown
80		h.check()
81	
82		if rem.calls != 1 {
83			t.Fatalf("expected exactly one remote switch on hub loss, got %d", rem.calls)
84		}
85		if rem.last != eps[1] {
86			t.Fatalf("switched remote = %v, want standby endpoint#2 %v", rem.last, eps[1])
87		}
88		if handshakes != 1 {
89			t.Fatalf("expected exactly one re-handshake on hub loss, got %d", handshakes)
90		}
91		if h.idx != 1 {
92			t.Fatalf("active index = %d, want 1 (advanced to the standby)", h.idx)
93		}
94	}
95	
96	// TestHubFailoverPartialDownNoFailover pins the load-bearing acceptance property that
97	// hub loss is EVERY path DOWN, distinct from a single-path failure (which the per-path
98	// schedulers already handle). With a 2-endpoint list and the settle dwell fully elapsed
99	// — so a broken "any path down" detector WOULD advance — one path UP and one path DOWN
100	// must take NO hub-failover action: no remote switch, no re-handshake, no index move.
101	// This is the case none of the both-Up / both-Down tests exercise; without it, a
102	// regression of allDownLocked from all-down to any-down would pass the whole suite.
103	func TestHubFailoverPartialDownNoFailover(t *testing.T) {
104		eps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820")
105		hp := []hubHealth{&fakeHealth{telemetry.StateUp}, &fakeHealth{telemetry.StateDown}}
106		rem := &recordingRemote{}
107		handshakes := 0
108		clk := &fakeClock{now: time.Unix(1000, 0)}
109		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
110	
111		// Settle dwell elapsed: an any-down detector would fire here; an all-down one must not.
112		clk.advance(testSettle + time.Second)
113		h.check()
114	
115		if rem.calls != 0 || handshakes != 0 {
116			t.Fatalf("hub failover fired on a partial-down state (one path UP): remote switches=%d handshakes=%d — hub loss must require EVERY path down", rem.calls, handshakes)
117		}
118		if h.idx != 0 {
119			t.Fatalf("active index moved off 0 while a path was UP: %d (single-path loss must not advance the hub)", h.idx)
120		}
121	}
122	
123	// TestHubFailoverSingleEndpointNoAction is the GUARD: a SINGLE-endpoint list must take
124	// NO failover action even under sustained hub loss — no remote switch, no re-handshake,
125	// no index movement — so a one-concentrator deployment behaves EXACTLY as pre-T57. It is
126	// non-vacuous: absent the len<2 guard, the wrap arithmetic (0+1)%1==0 would "switch" to
127	// the same endpoint and fire a re-handshake, which this asserts never happens.
128	func TestHubFailoverSingleEndpointNoAction(t *testing.T) {
129		eps := mustEndpoints(t, "203.0.113.1:51820")
130		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
131		rem := &recordingRemote{}
132		handshakes := 0
133		clk := &fakeClock{now: time.Unix(1000, 0)}
134		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
135	
136		for i := 0; i < 5; i++ {
137			clk.advance(time.Minute)
138			h.check()
139		}
140		if rem.calls != 0 {
141			t.Fatalf("single-endpoint list switched the remote %d times, want 0", rem.calls)
142		}
143		if handshakes != 0 {
144			t.Fatalf("single-endpoint list re-handshaked %d times, want 0", handshakes)
145		}
146		if h.idx != 0 {
147			t.Fatalf("single-endpoint list moved active index to %d, want 0", h.idx)
148		}
149	}
150	
151	// TestHubFailoverReArmsAndWraps proves detection re-arms against the NEW active endpoint
152	// and, at the end of the list, WRAPS to index 0 (the documented end-of-list policy). With
153	// a 2-endpoint list held fully DOWN, successive settle-separated checks advance 0→1→0.
154	func TestHubFailoverReArmsAndWraps(t *testing.T) {
155		eps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820")
156		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
157		rem := &recordingRemote{}
158		handshakes := 0
159		clk := &fakeClock{now: time.Unix(1000, 0)}
160		h := newHubFailover(eps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
161	
162		// First advance: 0 → 1 (settle since construction has elapsed).
163		clk.advance(testSettle + time.Second)
164		h.check()
165		if h.idx != 1 || rem.last != eps[1] || rem.calls != 1 {
166			t.Fatalf("first advance: idx=%d last=%v calls=%d, want idx=1 last=%v calls=1", h.idx, rem.last, rem.calls, eps[1])
167		}
168	
169		// Re-arm on the new endpoint, still fully down: after another settle, wrap 1 → 0.
170		clk.advance(testSettle + time.Second)
171		h.check()
172		if h.idx != 0 || rem.last != eps[0] || rem.calls != 2 {
173			t.Fatalf("wrap advance: idx=%d last=%v calls=%d, want idx=0 last=%v calls=2 (wrap to index 0)", h.idx, rem.last, rem.calls, eps[0])
174		}
175		if handshakes != 2 {
176			t.Fatalf("re-handshakes=%d, want 2 (one per advance)", handshakes)
177		}
178	}
179	
180	// TestHubFailoverSettleDwellDefersReAdvance proves the settle dwell prevents a premature
181	// second advance: right after a switch, a STILL-DOWN reading (which is expected while the
182	// new endpoint's echoes have not yet returned) must NOT skip to the next endpoint until
183	// the dwell elapses. Without this, a healthy standby would be skipped on the very next
184	// tick before its liveness could recover.
185	func TestHubFailoverSettleDwellDefersReAdvance(t *testing.T) {
186		realEps := mustEndpoints(t, "203.0.113.1:51820", "198.51.100.7:51820", "192.0.2.9:51820")
187		hp := []hubHealth{&fakeHealth{telemetry.StateDown}, &fakeHealth{telemetry.StateDown}}
188		rem := &recordingRemote{}
189		handshakes := 0
190		clk := &fakeClock{now: time.Unix(1000, 0)}
191		h := newHubFailover(realEps, hp, rem, func() { handshakes++ }, clk, testSettle, discardLogger(t))
192	
193		// First advance 0 → 1.
194		clk.advance(testSettle + time.Second)
195		h.check()
196		if rem.calls != 1 || h.idx != 1 {
197			t.Fatalf("first advance: calls=%d idx=%d, want 1 and 1", rem.calls, h.idx)
198		}
199	
200		// Within the dwell (< settle since the switch): no second advance despite still-down.
201		clk.advance(testSettle - time.Millisecond)
202		h.check()
203		if rem.calls != 1 || h.idx != 1 {
204			t.Fatalf("advanced within settle dwell: calls=%d idx=%d, want no change (1,1)", rem.calls, h.idx)
205		}
206	
207		// Dwell elapsed: now advance 1 → 2.
208		clk.advance(2 * time.Millisecond)
209		h.check()
210		if rem.calls != 2 || h.idx != 2 || rem.last != realEps[2] {
211			t.Fatalf("advance after dwell: calls=%d idx=%d last=%v, want 2, 2, %v", rem.calls, h.idx, rem.last, realEps[2])
212		}
213	}
